export const Navbar = ({ children, className }: NavbarProps) => {
  const ref = useRef<HTMLDivElement>(null);
  const { scrollY } = useScroll({
    target: ref,
    offset: ["start start", "end start"],
  });
  const [visible, setVisible] = useState<boolean>(false);

  useMotionValueEvent(scrollY, "change", (latest) => {
    setVisible(latest > 100);
  });

  return (
    <motion.div
      ref={ref}
      className={cn(
        // ⬇️ Changed from sticky with white backdrop to fully transparent container
        "fixed top-6 inset-x-0 z-50 flex justify-center bg-transparent pointer-events-none",
        className
      )}
    >
      {/* Children still animate normally, but we pass visibility */}
      {React.Children.map(children, (child) =>
        React.isValidElement(child)
          ? React.cloneElement(
              child as React.ReactElement<{ visible?: boolean }>,
              { visible }
            )
          : child
      )}
    </motion.div>
  );
};

export const NavBody = ({ children, className, visible }: NavBodyProps) => {
  return (
    <motion.div
      animate={{
        backdropFilter: "blur(8px)",
        backgroundColor: visible
          ? "rgba(255, 255, 255, 0.65)" // ⬅️ semi-transparent when scrolled
          : "rgba(255, 255, 255, 0.35)", // ⬅️ lighter transparent at top
        y: visible ? 10 : 0,
        scale: visible ? 0.98 : 1,
        boxShadow: visible
          ? "0 4px 30px rgba(140, 82, 255, 0.2)" // soft purple glow
          : "none",
      }}
      transition={{
        type: "spring",
        stiffness: 200,
        damping: 35,
      }}
      className={cn(
        "pointer-events-auto relative z-[60] mx-auto flex w-full max-w-5xl flex-row items-center justify-between rounded-full px-6 py-3",
        "border border-white/30 shadow-sm backdrop-blur-md",
        className
      )}
    >
      {children}
    </motion.div>
  );
};
